import functools
import json
import redis

_redis = redis.Redis(host='localhost', port=6379, db=0)

def cached(ttl: int = 300, prefix: str = 'cache'):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            key = f'{prefix}:{func.__name__}:{json.dumps(args)}:{json.dumps(kwargs)}'
            cached_value = _redis.get(key)
            if cached_value:
                return json.loads(cached_value)
            result = func(*args, **kwargs)
            _redis.setex(key, ttl, json.dumps(result))
            return result
        return wrapper
    return decorator

import time
import redis
from flask import request, jsonify

_redis = redis.Redis(host='localhost', port=6379, db=0)

def rate_limit(limit: int = 100, window: int = 60):
    def decorator(f):
        def wrapper(*args, **kwargs):
            key = f'rate:{request.remote_addr}:{f.__name__}'
            current = _redis.incr(key)
            if current == 1:
                _redis.expire(key, window)
            if current > limit:
                return jsonify({'error': 'Rate limit exceeded'}), 429
            return f(*args, **kwargs)
        return wrapper
    return decorator

